X	enum {READ, VERIFY, COPY, COPYVERIFY} op = READ;
X	sig_t oldsig;
X	int ch, needeof;
X	char *buff, *inf;
X
X	guesslen = 1;
X	while ((ch = getopt(argc, argv, "cs:vx")) != -1)
X		switch((char)ch) {
X		case 'c':
X			op = COPYVERIFY;
X			break;
X		case 's':
X			maxblk = atoi(optarg);
X			if (maxblk <= 0) {
