X		break;
X	default:
X		usage();
X	}
X
X	if ((inp = open(inf, O_RDONLY, 0)) < 0)
X		err(1, "%s", inf);
X
X	buff = getspace(maxblk);
X
X	if (op == VERIFY) {
X		verify(inp, outp, buff);
X		exit(0);
X	}
X
X	if ((oldsig = signal(SIGINT, SIG_IGN)) != SIG_IGN)
X		(void) signal(SIGINT, intr);
X
X	needeof = 0;
X	for (lastnread = NOCOUNT;;) {
